ALTER TABLE public.mib_to_implicit
  ADD CONSTRAINT "mib_to_implicit_mib_id_fkey" FOREIGN KEY ("mib_id") REFERENCES public.mib ("id") ON DELETE CASCADE,
  ADD CONSTRAINT "mib_to_implicit_implicit_id_fkey" FOREIGN KEY ("implicit_id") REFERENCES public.implicit ("id") ON DELETE CASCADE,
