ALTER TABLE public.mib_to_import
  ADD CONSTRAINT "mib_to_import_mib_id_fkey" FOREIGN KEY ("mib_id") REFERENCES public.mib ("id") ON DELETE CASCADE,
  ADD CONSTRAINT "mib_to_import_import_id_fkey" FOREIGN KEY ("import_id") REFERENCES public.import ("id") ON DELETE CASCADE,
  ADD CONSTRAINT "mib_imp" UNIQUE NULLS NOT DISTINCT ("mib_id", "import_id");

ALTER TABLE public.mib_to_module_compliance
  ADD CONSTRAINT "mib_to_module_compliance_mib_id_fkey" FOREIGN KEY ("mib_id") REFERENCES public.mib ("id") ON DELETE CASCADE,
  ADD CONSTRAINT "mib_to_module_compliance_module_compliance_id_fkey" FOREIGN KEY ("module_compliance_id") REFERENCES public.module_compliance ("id") ON DELETE CASCADE,
