  ADD CONSTRAINT "mib_to_module_compliance_module_compliance_module_group_id_fkey" FOREIGN KEY ("module_compliance_module_group_id") REFERENCES public.module_compliance_module_group ("id") ON DELETE CASCADE,
  ADD CONSTRAINT "mib_to_module_compliance_module_compliance_module_object_id_fkey" FOREIGN KEY ("module_compliance_module_object_id") REFERENCES public.module_compliance_module_object ("id") ON DELETE CASCADE,
  ADD CONSTRAINT "mib_mc" UNIQUE NULLS NOT DISTINCT ("mib_id", "module_compliance_id", "module_compliance_module_id", "module_compliance_module_group_id", "module_compliance_module_object_id");

ALTER TABLE public.mib_to_module_identity
  ADD CONSTRAINT "mib_to_module_identity_mib_id_fkey" FOREIGN KEY ("mib_id") REFERENCES public.mib ("id") ON DELETE CASCADE,
